{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-citation-interleaving-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的进料流股 feed-31 缺少必要规格、以及已选中的分离器 separator-3 在固定压力模式下缺少操作压力目标这两类问题生成候选提案；下游 vapor-31 的警告被视为上游未解导致的从属现象，本次仅提出局部、可审查的占位式补全建议。",
  "answers": [
    {
      "summary": "建议先在 feed-31 上补充流量规格占位，再在 separator-3 上补充固定压力目标占位，以直接对应当前两条错误诊断。",
      "issues": [
        {
          "title": "feed-31 缺少流量规格",
          "diagnostic": "Feed To Heater is missing flow rate specification.",
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "separator-3 固定压力模式缺少操作压力目标",
          "diagnostic": "Hot Separator is configured for fixed pressure mode but the operating pressure target is missing.",
          "citations": [
            "diag-2",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-31 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-31"
          },
          "rationale": "该流股已存在压力规格，但诊断明确指出缺少流量规格；在不臆造数值的前提下，添加流量占位可将缺项显式化，便于后续人工填写并解除上游求解阻塞。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "status": "missing",
                "note": "Provide feed flow rate specification for Feed To Heater."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 separator-3 添加固定压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-3"
          },
          "rationale": "该单元已配置为 fixed pressure mode，但缺少与该模式配套的操作压力目标；增加参数占位可保持当前控制模式不变，仅补足直接缺失项。",
          "patch": {
            "parameter_placeholders": {
              "operating_pressure_kpa": {
                "required": true,
                "status": "missing",
                "note": "Provide operating pressure target for fixed pressure mode."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        }
      ],
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-1",
        "flowdoc-unit-2",
        "snapshot-1"
      ],
      "confidence": 0.93
    }
  ]
}
